import React, { useState, useMemo, useEffect } from "react";
import { useData } from "../lib/DataContext";
import { Play, Square, Clock, X } from "lucide-react";
import { format, differenceInMinutes, parseISO } from "date-fns";
import { es } from "date-fns/locale";

function LiveTimer({ clockIn }) {
  const [elapsed, setElapsed] = useState("");
  useEffect(() => {
    const tick = () => {
      const start = new Date(clockIn);
      const mins  = differenceInMinutes(new Date(), start);
      const h = Math.floor(mins / 60);
      const m = mins % 60;
      setElapsed(`${h}h ${m.toString().padStart(2,"0")}m`);
    };
    tick();
    const id = setInterval(tick, 30_000);
    return () => clearInterval(id);
  }, [clockIn]);
  return <span className="pulse" style={{ color: "var(--success)", fontFamily: "var(--font-mono)", fontSize: 13 }}>● {elapsed}</span>;
}

function ClockInModal({ onClose, onSave, mechanics, workOrders }) {
  const [mechanicId, setMechanicId] = useState("");
  const [workOrderId, setWorkOrderId] = useState("");

  const activeOrders = workOrders.filter(w => w.status !== "Completado" && w.status !== "Cancelado");

  const handleSave = () => {
    if (!mechanicId || !workOrderId) { alert("Selecciona mecánico y orden."); return; }
    onSave({ mechanicId, workOrderId });
  };

  return (
    <div className="modal-overlay" onClick={e => e.target === e.currentTarget && onClose()}>
      <div className="modal">
        <div className="modal-header">
          <span className="modal-title" style={{ color: "var(--success)" }}>⏱ Iniciar Trabajo</span>
          <button className="btn btn-icon btn-ghost" onClick={onClose}><X size={18} /></button>
        </div>
        <div className="modal-body">
          <div className="form-group">
            <label className="form-label">Mecánico</label>
            <select className="form-input" value={mechanicId} onChange={e => setMechanicId(e.target.value)}>
              <option value="">Seleccionar mecánico…</option>
              {mechanics.filter(m => m.active === "true").map(m => (
                <option key={m.id} value={m.id}>{m.name} — {m.role}</option>
              ))}
            </select>
          </div>
          <div className="form-group">
            <label className="form-label">Orden de trabajo</label>
            <select className="form-input" value={workOrderId} onChange={e => setWorkOrderId(e.target.value)}>
              <option value="">Seleccionar orden…</option>
              {activeOrders.map(wo => (
                <option key={wo.id} value={wo.id}>
                  {wo.id} — {wo.equipmentName} — {wo.title}
                </option>
              ))}
            </select>
          </div>
          <div style={{ padding: "12px 14px", background: "rgba(61,202,126,0.08)", border: "1px solid rgba(61,202,126,0.2)", borderRadius: "var(--radius)", fontSize: 13, color: "var(--success)", fontFamily: "var(--font-mono)" }}>
            Hora de inicio: {format(new Date(), "HH:mm:ss")}
          </div>
        </div>
        <div className="modal-footer">
          <button className="btn btn-ghost" onClick={onClose}>Cancelar</button>
          <button className="btn btn-success" onClick={handleSave}>
            <Play size={14} /> Iniciar
          </button>
        </div>
      </div>
    </div>
  );
}

function ClockOutModal({ entry, onClose, onSave }) {
  const [notes, setNotes] = useState("");
  return (
    <div className="modal-overlay" onClick={e => e.target === e.currentTarget && onClose()}>
      <div className="modal">
        <div className="modal-header">
          <span className="modal-title" style={{ color: "var(--danger)" }}>⏹ Terminar Trabajo</span>
          <button className="btn btn-icon btn-ghost" onClick={onClose}><X size={18} /></button>
        </div>
        <div className="modal-body">
          <div style={{ padding: "14px", background: "var(--bg3)", borderRadius: "var(--radius)", fontSize: 13 }}>
            <div style={{ marginBottom: 4, fontWeight: 500 }}>{entry.mechanicName}</div>
            <div style={{ color: "var(--text3)", fontFamily: "var(--font-mono)", fontSize: 12 }}>
              Orden: {entry.workOrderId} · Inicio: {entry.clockIn?.split(" ")[1]}
            </div>
            <div style={{ marginTop: 6 }}><LiveTimer clockIn={entry.clockIn} /></div>
          </div>
          <div className="form-group">
            <label className="form-label">Notas del trabajo</label>
            <textarea className="form-input" rows={3} value={notes} onChange={e => setNotes(e.target.value)} placeholder="¿Qué se realizó?" />
          </div>
        </div>
        <div className="modal-footer">
          <button className="btn btn-ghost" onClick={onClose}>Cancelar</button>
          <button className="btn btn-danger" onClick={() => onSave(entry.id, notes)}>
            <Square size={14} /> Finalizar
          </button>
        </div>
      </div>
    </div>
  );
}

export default function TimeTracking() {
  const { timeEntries, mechanics, workOrders, clockIn, clockOut, loading } = useData();
  const [showClockIn, setShowClockIn] = useState(false);
  const [clockingOut, setClockOutEntry] = useState(null);

  const activeEntries = useMemo(() => timeEntries.filter(t => t.clockIn && !t.clockOut), [timeEntries]);
  const completed     = useMemo(() =>
    [...timeEntries.filter(t => t.clockOut)].sort((a,b) => new Date(b.clockOut) - new Date(a.clockOut)).slice(0, 30),
    [timeEntries]
  );

  const totalHrs = useMemo(() =>
    completed.reduce((s, t) => s + (parseFloat(t.hours) || 0), 0).toFixed(1),
    [completed]
  );

  const handleClockIn = async ({ mechanicId, workOrderId }) => {
    await clockIn({ mechanicId, workOrderId });
    setShowClockIn(false);
  };
  const handleClockOut = async (entryId, notes) => {
    await clockOut(entryId, notes);
    setClockOutEntry(null);
  };

  if (loading) return <div className="empty-state"><p>Cargando…</p></div>;

  return (
    <div>
      <div className="page-header">
        <div>
          <h1 className="page-title">Registro de Tiempo</h1>
          <p className="page-subtitle">{activeEntries.length} mecánico{activeEntries.length !== 1 ? "s" : ""} trabajando ahora</p>
        </div>
        <button className="btn btn-success" onClick={() => setShowClockIn(true)}>
          <Play size={16} /> Registrar Entrada
        </button>
      </div>

      {/* Stats */}
      <div className="grid-3 mb-24">
        <div className="stat-card" style={{ "--accent-line": "var(--success)" }}>
          <span className="stat-label">Activos ahora</span>
          <span className="stat-value">{activeEntries.length}</span>
          <span className="stat-sub">mecánicos en turno</span>
        </div>
        <div className="stat-card" style={{ "--accent-line": "var(--info)" }}>
          <span className="stat-label">Entradas totales</span>
          <span className="stat-value">{timeEntries.length}</span>
          <span className="stat-sub">registros históricos</span>
        </div>
        <div className="stat-card" style={{ "--accent-line": "var(--accent)" }}>
          <span className="stat-label">Horas completadas</span>
          <span className="stat-value">{totalHrs}</span>
          <span className="stat-sub">últimas 30 entradas</span>
        </div>
      </div>

      {/* Active entries */}
      {activeEntries.length > 0 && (
        <div className="section-gap">
          <div className="card-title mb-16">En Curso</div>
          <div className="grid-2">
            {activeEntries.map(te => (
              <div key={te.id} className="card" style={{ borderLeft: "3px solid var(--success)" }}>
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start" }}>
                  <div>
                    <div style={{ fontWeight: 600, fontSize: 16, marginBottom: 4 }}>{te.mechanicName}</div>
                    <div style={{ fontSize: 12, color: "var(--text3)", fontFamily: "var(--font-mono)", marginBottom: 8 }}>
                      {te.workOrderId}
                    </div>
                    <LiveTimer clockIn={te.clockIn} />
                  </div>
                  <button className="btn btn-danger btn-sm" onClick={() => setClockOutEntry(te)}>
                    <Square size={12} /> Terminar
                  </button>
                </div>
                <div style={{ marginTop: 12, fontSize: 12, color: "var(--text3)", fontFamily: "var(--font-mono)" }}>
                  Inicio: {te.clockIn}
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* History */}
      <div className="card-title mb-16">Historial Reciente</div>
      <div className="card" style={{ padding: 0, overflow: "hidden" }}>
        <div className="table-wrap">
          <table>
            <thead>
              <tr>
                <th>Mecánico</th>
                <th>Orden</th>
                <th>Entrada</th>
                <th>Salida</th>
                <th>Horas</th>
                <th>Notas</th>
                <th>Facturable</th>
              </tr>
            </thead>
            <tbody>
              {completed.length === 0 && (
                <tr><td colSpan={7} style={{ textAlign: "center", padding: 40, color: "var(--text3)" }}>Sin registros completados</td></tr>
              )}
              {completed.map(te => (
                <tr key={te.id}>
                  <td style={{ fontWeight: 500 }}>{te.mechanicName}</td>
                  <td><span style={{ fontSize: 11, fontFamily: "var(--font-mono)", color: "var(--text3)" }}>{te.workOrderId}</span></td>
                  <td><span style={{ fontSize: 12, fontFamily: "var(--font-mono)" }}>{te.clockIn}</span></td>
                  <td><span style={{ fontSize: 12, fontFamily: "var(--font-mono)" }}>{te.clockOut}</span></td>
                  <td>
                    <span style={{ fontFamily: "var(--font-mono)", fontWeight: 600, color: "var(--accent)" }}>
                      {te.hours ? `${te.hours}h` : "—"}
                    </span>
                  </td>
                  <td style={{ color: "var(--text2)", maxWidth: 180, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>
                    {te.notes || "—"}
                  </td>
                  <td>
                    {te.billable === "true"
                      ? <span className="badge badge-success">Sí</span>
                      : <span className="badge badge-neutral">No</span>
                    }
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>

      {showClockIn && (
        <ClockInModal
          onClose={() => setShowClockIn(false)}
          onSave={handleClockIn}
          mechanics={mechanics}
          workOrders={workOrders}
        />
      )}
      {clockingOut && (
        <ClockOutModal
          entry={clockingOut}
          onClose={() => setClockOutEntry(null)}
          onSave={handleClockOut}
        />
      )}
    </div>
  );
}
